import * as React from 'react';
import { PackageIcon } from 'lucide-react';
import { useTranslationAdapter } from '@adapters/useTranslationAdapter';
import { useInventory, useInventoryFilters, INVENTORY_PAGE_SIZE } from '@features/inventory';
import type { StockTab } from '@features/inventory';
import { PermissionGuard, useEffectiveRole } from '@features/auth';
import { useWarehouses } from '@features/inventory';
import { cn } from '@shared/lib/cn';
import { telemetry } from '@shared/lib/observability';
import { Button, Pagination, Input } from '@shared/ui/primitives';
import { Card, ConfirmDialog, EmptyState, Select, SelectTrigger, SelectValue, SelectContent, SelectItem } from '@shared/ui/composed';
import { SectionErrorBoundary } from '@app/providers';
import { InventoryTableWidget } from '@widgets/inventory';
import { AuditLogPanel } from '@widgets/audit';
import { InventoryCreateDialog, InventoryEditDialog, StockAdjustDialog, MovementsHistoryPanel, StockTransferDialog } from '@features/inventory';
import { useInventoryPageActions } from './useInventoryPageActions';
import styles from '@shared/styles/themes/pages/Inventory.module.scss';

export function InventoryPage(): React.ReactElement {
  const { translate: t } = useTranslationAdapter();
  const role = useEffectiveRole();
  const { data: warehouses } = useWarehouses();

  const {
    createOpen, setCreateOpen,
    editItem, setEditItem,
    adjustItem, setAdjustItem,
    transferItem, setTransferItem,
    deleteId, setDeleteId,
    historyItem, setHistoryItem,
    isDeleting,
    handleExport,
    handleDelete,
    onEdit, onAdjustStock, onDelete, onTransfer,
  } = useInventoryPageActions(role);

  const {
    search, setSearch, tab, setTab, page, setPage,
    warehouseFilter, setWarehouseFilter,
    debouncedSearch, params,
  } = useInventoryFilters();

  const { data: inventory, isPending, isError, error, refetch } = useInventory(params);

  const inventoryItems = inventory?.data ?? [];
  const serverTotal = inventory?.total ?? 0;
  const pageCount = Math.max(1, Math.ceil(serverTotal / INVENTORY_PAGE_SIZE));

  const tabs = React.useMemo(() => [
    { id: 'all' as StockTab, labelKey: 'inventory.allProducts', count: tab === 'all' ? serverTotal : 0 },
    { id: 'low' as StockTab, labelKey: 'inventory.lowStockTab', count: tab === 'low' ? serverTotal : 0 },
    { id: 'out' as StockTab, labelKey: 'inventory.outOfStockTab', count: tab === 'out' ? serverTotal : 0 },
  ], [tab, serverTotal]);

  if (isError) {
    if (error instanceof Error) {
      telemetry.captureException(error, { source: 'InventoryPage' });
    } else {
      telemetry.captureMessage('Inventory fetch error', { source: 'InventoryPage', error });
    }
    return (
      <div className={styles['errorContainer']} role="alert" aria-live="assertive">
        <p>{t('common.errorLoadingData')}</p>
        <Button variant="outline" size="sm" onClick={(): void => { void refetch(); }}>
          {t('common.retry')}
        </Button>
      </div>
    );
  }

  return (
    <div className={styles['page']}>
      <header className={styles['header']}>
        <div className={styles['headerText']}>
          <h1 className={styles['title']}>{t('inventory.title')}</h1>
          <p className={styles['subtitle']}>{t('inventory.subtitle')}</p>
        </div>
        <div className={styles['headerActions']}>
          {warehouses && warehouses.length > 0 && (
            <Select
              value={warehouseFilter ?? ''}
              onValueChange={(val) => { setWarehouseFilter(val !== '' ? val : null); }}
            >
              <SelectTrigger size="sm" aria-label={t('inventory.filterByWarehouse')}>
                <SelectValue placeholder={t('inventory.allWarehouses')} />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">{t('inventory.allWarehouses')}</SelectItem>
                {warehouses
                  .filter((w) => w.isActive)
                  .map((w) => (
                    <SelectItem key={w.id} value={w.id}>
                      {w.name}
                    </SelectItem>
                  ))}
              </SelectContent>
            </Select>
          )}
          <PermissionGuard permission="export:csv">
            <Button variant="outline" size="sm" onClick={() => { handleExport(inventoryItems); }}>
              {t('inventory.exportCsv')}
            </Button>
          </PermissionGuard>
          <PermissionGuard permission="create:inventory">
            <Button size="sm" onClick={() => { setCreateOpen(true); }}>
              {`+ ${t('inventory.addProduct')}`}
            </Button>
          </PermissionGuard>
        </div>
      </header>

      <Card noPadding className={styles['tableCard']}>
        <div className={styles['controls']}>
          <div className={styles['searchBox']}>
            <Input
              type="search"
              placeholder={`${t('common.filter')} SKU, ${t('inventory.name').toLowerCase()}…`}
              value={search}
              onChange={(e: React.ChangeEvent<HTMLInputElement>) => { setSearch(e.target.value); }}
              aria-label={t('common.filter')}
            />
          </div>
          <div className={styles['tabs']} role="tablist">
            {tabs.map((tb) => (
              <Button
                key={tb.id}
                id={`inventory-tab-${tb.id}`}
                role="tab"
                aria-selected={tab === tb.id}
                aria-controls="inventory-tabpanel"
                onClick={() => { setTab(tb.id); }}
                variant="ghost"
                className={cn(styles['tab'], tab === tb.id && styles['tabActive'])}
              >
                {t(tb.labelKey)}
                <span className={styles['tabCount']}>{tb.count}</span>
              </Button>
            ))}
          </div>
        </div>

        <div id="inventory-tabpanel" role="tabpanel" aria-labelledby={`inventory-tab-${tab}`}>
        <SectionErrorBoundary label="Inventory">
          {!isPending && inventoryItems.length === 0 ? (
            <EmptyState
              icon={<PackageIcon size={24} />}
              title={t('inventory.emptyTitle')}
              description={t('inventory.emptyDescription')}
              action={
                debouncedSearch
                  ? undefined
                  : { label: `+ ${t('inventory.addProduct')}`, onClick: (): void => { setCreateOpen(true); } }
              }
            />
          ) : (
            <InventoryTableWidget
              data={inventoryItems}
              isPending={isPending}
              onEdit={onEdit}
              onAdjustStock={onAdjustStock}
              onDelete={onDelete}
              onViewHistory={(item) => { setHistoryItem(item); }}
              onTransfer={onTransfer}
            />
          )}
        </SectionErrorBoundary>
        </div>

        <div className={styles['tableFooter']}>
          <span>
            {serverTotal > 0
              ? `${Math.min((page - 1) * INVENTORY_PAGE_SIZE + 1, serverTotal)}–${Math.min(page * INVENTORY_PAGE_SIZE, serverTotal)}`
              : '0–0'
            } / {serverTotal} {t('inventory.products').toLowerCase()}
          </span>
          <Pagination page={page} pageCount={pageCount} onPageChange={setPage} />
        </div>
      </Card>

      <PermissionGuard permission="view:audit">
        <Card noPadding className={cn(styles['tableCard'], styles['auditCard'])}>
          <div className={styles['auditCardHeader']}>
            <h3 className={styles['auditTitle']}>{t('common.auditLog')}</h3>
          </div>
          <div className={styles['auditCardBody']}>
            <AuditLogPanel entityType="inventory" />
          </div>
        </Card>
      </PermissionGuard>

      <MovementsHistoryPanel
        item={historyItem}
        open={historyItem !== null}
        onOpenChange={(open) => { if (!open) setHistoryItem(null); }}
      />
      <InventoryCreateDialog open={createOpen} onOpenChange={setCreateOpen} />
      <InventoryEditDialog
        item={editItem}
        open={editItem !== null}
        onOpenChange={(open) => { if (!open) setEditItem(null); }}
      />
      <StockAdjustDialog
        item={adjustItem}
        open={adjustItem !== null}
        onOpenChange={(open) => { if (!open) setAdjustItem(null); }}
      />
      <StockTransferDialog
        item={transferItem}
        open={transferItem !== null}
        onOpenChange={(open) => { if (!open) setTransferItem(null); }}
      />
      <ConfirmDialog
        open={deleteId !== null}
        onOpenChange={(open) => { if (!open) setDeleteId(null); }}
        title={t('inventory.deleteItem')}
        description={t('common.cannotUndo')}
        onConfirm={handleDelete}
        isPending={isDeleting}
      />
    </div>
  );
}
